#include <bits/stdc++.h>
using namespace std;int n;vector<int>a;int op[4];long long mx=LLONG_MIN,mn=LLONG_MAX;
void bt(int idx,long long acc){if(idx==n){mx=max(mx,acc);mn=min(mn,acc);return;}for(int k=0;k<4;k++)if(op[k]){op[k]--;long long v=acc;if(k==0)v+=a[idx];else if(k==1)v-=a[idx];else if(k==2)v*=a[idx];else v/=a[idx];bt(idx+1,v);op[k]++;}}
int main(){cin>>n;a.resize(n);for(auto&x:a)cin>>x;for(int i=0;i<4;i++)cin>>op[i];bt(1,a[0]);cout<<mx<<"\n"<<mn<<"\n";}
